214→    case "GPROMOTE":
215→      return { type: "unimplemented", feature: "Guild management" };
216→    case "MAIL":
217→      return { type: "unimplemented", feature: "Mail" };
218→    case "ROLL": {
219→      const parts = rest.split(" ").filter(Boolean);
220→      if (parts.length >= 2)
221→        return {
222→          type: "roll",
223→          min: parseInt(parts[0]!, 10),
224→          max: parseInt(parts[1]!, 10),
225→        };
226→      if (parts.length === 1)
227→        return { type: "roll", min: 1, max: parseInt(parts[0]!, 10) };
228→      return { type: "roll", min: 1, max: 100 };
229→    }
230→    default:
231→      return line ? { type: "chat", message: line } : undefined;
232→  }
233→}
