240→function drainText(events: RingBuffer<EventEntry>): string[] {
241→  return events.drain().flatMap((e) => (e.text !== undefined ? [e.text] : []));
242→}
243→
244→function drainJson(events: RingBuffer<EventEntry>): string[] {
245→  return events.drain().map((e) => e.json);
246→}
