388→      writeLines(
389→        socket,
390→        entities.map((e) => JSON.stringify(formatNearbyObj(e))),
391→      );
392→      return false;
393→    }
394→    case "friends": {
395→      const friends = handle.getFriends();
396→      writeLines(socket, formatFriendList(friends).split("\n"));
397→      return false;
398→    }
