436→function objectTypeName(type: ObjectType): string {
437→  switch (type) {
438→    case ObjectType.UNIT:
439→      return "NPC";
440→    case ObjectType.PLAYER:
441→      return "Player";
442→    default:
443→      return `type ${type}`;
