447→function formatNearbyLine(entity: Entity): string {
448→  if (
449→    entity.objectType === ObjectType.UNIT ||
450→    entity.objectType === ObjectType.PLAYER
451→  ) {
452→    const unit = entity as UnitEntity;
453→    const name = entity.name ?? "Unknown";
454→    const kind = objectTypeName(entity.objectType);
455→    const level = unit.level > 0 ? `, level ${unit.level}` : "";
456→    const hp = `HP ${unit.health}/${unit.maxHealth}`;
457→    const pos = entity.position
458→      ? ` at ${entity.position.x.toFixed(2)}, ${entity.position.y.toFixed(2)}, ${entity.position.z.toFixed(2)}`
459→      : "";
460→    return `${name} (${kind}${level}) ${hp}${pos}`;
461→  }
462→  if (entity.objectType === ObjectType.GAMEOBJECT) {
463→    const name = entity.name ?? "Unknown";
464→    const pos = entity.position
465→      ? ` at ${entity.position.x.toFixed(2)}, ${entity.position.y.toFixed(2)}, ${entity.position.z.toFixed(2)}`
466→      : "";
467→    return `${name} (GameObject)${pos}`;
468→  }
469→  return `Entity 0x${entity.guid.toString(16)} (${objectTypeName(entity.objectType)})`;
470→}
471→
472→function objectTypeString(type: ObjectType): string {
473→  switch (type) {
474→    case ObjectType.UNIT:
475→      return "unit";
476→    case ObjectType.PLAYER:
477→      return "player";
478→    case ObjectType.GAMEOBJECT:
479→      return "gameobject";
480→    default:
481→      return "object";
482→  }
483→}
484→
485→function formatNearbyObj(entity: Entity): Record<string, unknown> {
486→  const obj: Record<string, unknown> = {
487→    guid: `0x${entity.guid.toString(16)}`,
488→    type: objectTypeString(entity.objectType),
489→    name: entity.name,
490→  };
491→  if (
492→    entity.objectType === ObjectType.UNIT ||
493→    entity.objectType === ObjectType.PLAYER
494→  ) {
495→    const unit = entity as UnitEntity;
496→    obj["level"] = unit.level;
497→    obj["health"] = unit.health;
498→    obj["maxHealth"] = unit.maxHealth;
499→  }
500→  if (entity.objectType === ObjectType.GAMEOBJECT) {
501→    obj["gameObjectType"] = (entity as GameObjectEntity).gameObjectType;
502→  }
503→  if (entity.position) {
504→    obj["x"] = entity.position.x;
505→    obj["y"] = entity.position.y;
506→    obj["z"] = entity.position.z;
507→  }
508→  return obj;
509→}
