511→function formatGroupEventObj(event: GroupEvent): Record<string, unknown> {
512→  switch (event.type) {
513→    case "invite_received":
514→      return { type: "GROUP_INVITE", from: event.from };
515→    case "command_result":
516→      return {
517→        type: "GROUP_COMMAND_RESULT",
