  1→import { createInterface } from "node:readline";
  2→import { ChatType } from "wow/protocol/opcodes";
  3→import type { WorldHandle } from "wow/client";
  4→import { parseCommand, type Command } from "ui/commands";
  5→import {
  6→  formatMessage,
