 20→  showEntityEvents: boolean;
 21→};
 22→
 23→export async function executeCommand(
 24→  state: TuiState,
 25→  cmd: Command,
 26→): Promise<boolean> {
 27→  switch (cmd.type) {
 28→    case "chat":
 29→      state.handle.sendInCurrentMode(cmd.message);
 30→      break;
 31→    case "say":
 32→      state.handle.sendSay(cmd.message);
 33→      break;
 34→    case "yell":
 35→      state.handle.sendYell(cmd.message);
 36→      break;
 37→    case "guild":
 38→      state.handle.sendGuild(cmd.message);
 39→      break;
 40→    case "party":
 41→      state.handle.sendParty(cmd.message);
 42→      break;
 43→    case "raid":
 44→      state.handle.sendRaid(cmd.message);
 45→      break;
 46→    case "emote":
 47→      state.handle.sendEmote(cmd.message);
 48→      break;
 49→    case "dnd":
 50→      state.handle.sendDnd(cmd.message);
 51→      break;
 52→    case "afk":
 53→      state.handle.sendAfk(cmd.message);
 54→      break;
 55→    case "whisper":
 56→      state.handle.sendWhisper(cmd.target, cmd.message);
 57→      state.lastWhisperFrom = cmd.target;
 58→      break;
 59→    case "reply":
 60→      if (!state.lastWhisperFrom) {
 61→        state.write(formatError("No one has whispered you yet.") + "\n");
 62→      } else {
 63→        state.handle.sendWhisper(state.lastWhisperFrom, cmd.message);
 64→      }
 65→      break;
 66→    case "channel": {
 67→      const channel = /^\d+$/.test(cmd.target)
 68→        ? state.handle.getChannel(parseInt(cmd.target, 10))
 69→        : cmd.target;
 70→      if (!channel) {
 71→        state.write(formatError(`Not in channel ${cmd.target}.`) + "\n");
 72→      } else {
 73→        state.handle.sendChannel(channel, cmd.message);
 74→      }
 75→      break;
 76→    }
 77→    case "who": {
 78→      const results = await state.handle.who(
 79→        cmd.target ? { name: cmd.target } : {},
 80→      );
 81→      state.write(formatWhoResults(results) + "\n");
 82→      break;
 83→    }
 84→    case "invite":
 85→      state.handle.invite(cmd.target);
 86→      break;
 87→    case "kick":
 88→      state.handle.uninvite(cmd.target);
 89→      break;
 90→    case "leave":
 91→      state.handle.leaveGroup();
 92→      break;
 93→    case "leader":
 94→      state.handle.setLeader(cmd.target);
 95→      break;
 96→    case "accept":
 97→      state.handle.acceptInvite();
 98→      break;
 99→    case "decline":
100→      state.handle.declineInvite();
101→      break;
102→    case "quit":
103→      return true;
104→    case "tuicraft":
105→      if (cmd.subcommand === "entities") {
106→        if (cmd.value === "on") {
107→          state.showEntityEvents = true;
108→          state.write("[system] Entity events enabled\n");
109→        } else if (cmd.value === "off") {
110→          state.showEntityEvents = false;
111→          state.write("[system] Entity events disabled\n");
112→        } else {
113→          state.write("[system] Usage: /tuicraft entities on|off\n");
114→        }
115→      } else {
116→        state.write(`[system] Unknown tuicraft command: ${cmd.subcommand}\n`);
117→      }
118→      break;
119→    case "friends": {
120→      const friends = state.handle.getFriends();
121→      state.write(formatFriendList(friends) + "\n");
122→      break;
123→    }
124→    case "add-friend":
125→      state.handle.addFriend(cmd.target);
126→      break;
127→    case "remove-friend":
128→      state.handle.removeFriend(cmd.target);
129→      break;
130→    case "ignored": {
131→      const ignored = state.handle.getIgnored();
132→      state.write(formatIgnoreList(ignored) + "\n");
133→      break;
134→    }
135→    case "add-ignore":
136→      state.handle.addIgnore(cmd.target);
137→      break;
138→    case "remove-ignore":
139→      state.handle.removeIgnore(cmd.target);
140→      break;
141→    case "roll":
142→      state.handle.sendRoll(cmd.min, cmd.max);
143→      break;
144→    case "unimplemented":
145→      state.write(formatError(`${cmd.feature} is not yet implemented`) + "\n");
146→      break;
147→  }
148→  return false;
149→}
150→
151→export type TuiOptions = {
152→  input?: NodeJS.ReadableStream;
153→  write?: (s: string) => void;
154→};
155→
156→export function startTui(
157→  handle: WorldHandle,
158→  interactive: boolean,
159→  opts: TuiOptions = {},
160→): Promise<void> {
161→  const write = opts.write ?? ((s: string) => void process.stdout.write(s));
162→  const state: TuiState = {
163→    handle,
164→    write,
165→    lastWhisperFrom: undefined,
166→    showEntityEvents: false,
167→  };
168→
169→  return new Promise<void>((resolve) => {
170→    handle.onMessage((msg) => {
171→      if (msg.type === ChatType.WHISPER) state.lastWhisperFrom = msg.sender;
172→      const line = formatMessage(msg);
173→      write(interactive ? `\r\x1b[K${line}\n` : line + "\n");
174→      if (interactive) rl.prompt(true);
175→    });
176→
177→    handle.onGroupEvent((event) => {
178→      const line = formatGroupEvent(event);
179→      if (!line) return;
180→      write(interactive ? `\r\x1b[K${line}\n` : line + "\n");
181→      if (interactive) rl.prompt(true);
182→    });
183→
184→    handle.onEntityEvent((event) => {
185→      if (!state.showEntityEvents) return;
186→      const line = formatEntityEvent(event);
187→      if (!line) return;
188→      write(interactive ? `\r\x1b[K${line}\n` : line + "\n");
189→      if (interactive) rl.prompt(true);
190→    });
191→
192→    const rl = createInterface({
193→      input: opts.input ?? process.stdin,
194→      output: interactive ? process.stdout : undefined,
195→      prompt: interactive ? formatPrompt(handle.getLastChatMode()) : "",
196→      terminal: interactive,
197→    });
198→
199→    if (interactive) rl.prompt();
200→
201→    rl.on("line", async (input) => {
202→      try {
203→        if (await executeCommand(state, parseCommand(input.trim()))) {
204→          handle.close();
205→          rl.close();
206→          resolve();
207→          return;
208→        }
209→      } catch (err) {
210→        const msg = err instanceof Error ? err.message : String(err);
211→        write(formatError(msg) + "\n");
212→      }
213→      if (interactive) {
214→        rl.setPrompt(formatPrompt(handle.getLastChatMode()));
215→        rl.prompt();
216→      }
217→    });
218→
219→    rl.on("SIGINT", () => {
220→      handle.close();
221→      rl.close();
222→    });
223→
224→    rl.on("close", () => {
225→      handle.close();
226→      resolve();
227→    });
228→
229→    handle.closed.then(() => rl.close());
230→  });
231→}
