221→function drainWorldPackets(conn: WorldConn): void {
222→  while (true) {
223→    if (!conn.pendingHeader) {
224→      if (conn.buf.length < INCOMING_HEADER_SIZE) break;
225→      conn.pendingHeader = decryptIncomingHeader(
226→        conn.buf.drain(INCOMING_HEADER_SIZE),
227→        conn.arc4,
228→      );
229→    }
230→    const bodySize = conn.pendingHeader.size - 2;
231→    if (conn.buf.length < bodySize) break;
232→
233→    const { opcode } = conn.pendingHeader;
234→    conn.pendingHeader = undefined;
235→    try {
236→      conn.dispatch.handle(opcode, new PacketReader(conn.buf.drain(bodySize)));
237→    } catch (err) {
238→      if (err instanceof Error) {
239→        conn.onPacketError?.(opcode, err);
240→      }
241→    }
242→  }
243→}
