251→  challenge.uint32LE();
252→  const serverSeed = challenge.bytes(4);
253→
254→  const body = await buildWorldAuthPacket(
255→    config.account,
256→    auth.sessionKey,
257→    serverSeed,
258→    auth.realmId,
259→    config.clientSeed,
260→  );
261→  conn.socket.write(buildOutgoingPacket(GameOpcode.CMSG_AUTH_SESSION, body));
262→  conn.arc4 = new Arc4(auth.sessionKey);
263→
264→  const resp = await conn.dispatch.expect(GameOpcode.SMSG_AUTH_RESPONSE);
265→  const status = resp.uint8();
266→  if (status !== 0x0c) {
267→    const names: Record<number, string> = {
268→      0x0d: "system error",
269→      0x15: "account in use",
270→    };
271→    const label = names[status] ?? `status 0x${status.toString(16)}`;
272→    throw new Error(`World auth failed: ${label}`);
273→  }
274→}
