  1→import { inflateSync } from "node:zlib";
  2→import { PacketReader, PacketWriter } from "wow/protocol/packet";
  3→import { GameOpcode, ChatType } from "wow/protocol/opcodes";
  4→import {
  5→  parseChatMessage,
  6→  buildNameQuery,
  7→  parseNameQueryResponse,
  8→  parseChannelNotify,
  9→  parseRandomRoll,
 10→  parseServerBroadcast,
 11→  parseNotification,
 12→  type ChatMessage as RawChatMessage,
 13→} from "wow/protocol/chat";
 14→import { buildOutgoingPacket } from "wow/protocol/world";
 15→import {
 16→  parsePartyCommandResult,
 17→  parseGroupInvite,
 18→  parseGroupSetLeader,
 19→  parseGroupDecline,
 20→  parseGroupList,
 21→  parsePartyMemberStats,
 22→} from "wow/protocol/group";
 23→import { parseUpdateObject } from "wow/protocol/update-object";
 24→import { ObjectType } from "wow/protocol/entity-fields";
 25→import {
 26→  extractObjectFields,
 27→  extractUnitFields,
 28→  extractGameObjectFields,
 29→} from "wow/protocol/extract-fields";
 30→import {
 31→  buildCreatureQuery,
 32→  parseCreatureQueryResponse,
 33→  buildGameObjectQuery,
 34→  parseGameObjectQueryResponse,
 35→} from "wow/protocol/entity-queries";
 36→import {
 37→  parseContactList,
 38→  parseFriendStatus,
 39→  SocialFlag,
 40→  FriendStatus,
 41→  FriendResult,
 42→} from "wow/protocol/social";
 43→import type { FriendEntry } from "wow/friend-store";
 44→import type { IgnoreEntry } from "wow/ignore-store";
 45→import type { WorldConn } from "wow/client";
 46→
 47→export function sendPacket(
 48→  conn: WorldConn,
 49→  opcode: number,
 50→  body: Uint8Array = new Uint8Array(0),
 51→): void {
 52→  conn.socket.write(buildOutgoingPacket(opcode, body, conn.arc4));
 53→}
 54→
 55→export function handleTimeSync(conn: WorldConn, r: PacketReader): void {
 56→  const counter = r.uint32LE();
 57→  const elapsed = Date.now() - conn.startTime;
 58→  const w = new PacketWriter();
 59→  w.uint32LE(counter);
 60→  w.uint32LE(elapsed);
 61→  sendPacket(conn, GameOpcode.CMSG_TIME_SYNC_RESP, w.finish());
 62→}
 63→
 64→export function deliverMessage(
 65→  conn: WorldConn,
 66→  raw: RawChatMessage,
 67→  name: string,
 68→): void {
 69→  conn.onMessage?.({
 70→    type: raw.type,
 71→    sender: name,
 72→    message: raw.message,
 73→    channel: raw.channel,
 74→  });
 75→}
 76→
 77→export function resolveAndDeliver(conn: WorldConn, raw: RawChatMessage): void {
 78→  if (raw.senderGuidLow === 0) {
 79→    deliverMessage(conn, raw, "");
 80→    return;
 81→  }
 82→
 83→  if (conn.ignoreStore.has(raw.senderGuidLow)) return;
 84→
 85→  const cached = conn.nameCache.get(raw.senderGuidLow);
 86→  if (cached !== undefined) {
 87→    deliverMessage(conn, raw, cached);
 88→    return;
 89→  }
 90→
 91→  const pending = conn.pendingMessages.get(raw.senderGuidLow);
 92→  if (pending) {
 93→    pending.push(raw);
 94→  } else {
 95→    conn.pendingMessages.set(raw.senderGuidLow, [raw]);
 96→    sendPacket(
 97→      conn,
 98→      GameOpcode.CMSG_NAME_QUERY,
 99→      buildNameQuery(raw.senderGuidLow, raw.senderGuidHigh),
100→    );
101→  }
102→}
103→
104→export function handleChatMessage(conn: WorldConn, r: PacketReader): void {
105→  resolveAndDeliver(conn, parseChatMessage(r));
106→}
107→
108→export function handleRandomRoll(conn: WorldConn, r: PacketReader): void {
109→  const roll = parseRandomRoll(r);
110→  resolveAndDeliver(conn, {
111→    type: ChatType.ROLL,
112→    language: 0,
113→    senderGuidLow: roll.guidLow,
114→    senderGuidHigh: roll.guidHigh,
115→    message: `rolled ${roll.result} (${roll.min}-${roll.max})`,
116→  });
117→}
118→
119→export function handleGmChatMessage(conn: WorldConn, r: PacketReader): void {
120→  const raw = parseChatMessage(r, true);
121→  deliverMessage(conn, raw, raw.senderName ?? "");
122→}
123→
124→export function handleNameQueryResponse(
125→  conn: WorldConn,
126→  r: PacketReader,
127→): void {
128→  const result = parseNameQueryResponse(r);
129→
130→  const name = result.found && result.name ? result.name : "";
131→  conn.pendingNameQueries.delete(`player:${result.guidLow}`);
132→  if (result.found && result.name) {
133→    conn.nameCache.set(result.guidLow, result.name);
134→    for (const entity of conn.entityStore.all()) {
135→      if (
136→        entity.objectType === ObjectType.PLAYER &&
137→        Number(entity.guid & 0xffffffffn) === result.guidLow &&
138→        !entity.name
139→      ) {
140→        conn.entityStore.setName(entity.guid, result.name);
141→      }
142→    }
143→    for (const friend of conn.friendStore.all()) {
144→      if (
145→        Number(friend.guid & 0xffffffffn) === result.guidLow &&
146→        !friend.name
147→      ) {
148→        conn.friendStore.setName(friend.guid, result.name);
149→      }
150→    }
151→    for (const entry of conn.ignoreStore.all()) {
152→      if (Number(entry.guid & 0xffffffffn) === result.guidLow && !entry.name) {
153→        conn.ignoreStore.setName(entry.guid, result.name);
154→      }
155→    }
156→  }
157→
158→  const pending = conn.pendingMessages.get(result.guidLow);
159→  if (!pending) return;
160→  for (const raw of pending) deliverMessage(conn, raw, name);
161→  conn.pendingMessages.delete(result.guidLow);
162→}
163→
164→export function handleChannelNotify(conn: WorldConn, r: PacketReader): void {
165→  const event = parseChannelNotify(r);
166→  if (event.type === "joined") {
167→    conn.channels.push(event.channel);
168→  } else if (event.type === "left") {
169→    const idx = conn.channels.indexOf(event.channel);
170→    if (idx !== -1) conn.channels.splice(idx, 1);
171→  }
172→}
173→
174→export function handleMotd(conn: WorldConn, r: PacketReader): void {
175→  const lineCount = r.uint32LE();
176→  const lines: string[] = [];
177→  for (let i = 0; i < lineCount; i++) {
178→    lines.push(r.cString());
179→  }
180→  conn.onMessage?.({
181→    type: ChatType.SYSTEM,
182→    sender: "",
183→    message: lines.join("\n"),
184→  });
185→}
186→
187→export function handlePlayerNotFound(conn: WorldConn, r: PacketReader): void {
188→  const name = r.cString();
189→  conn.onMessage?.({
190→    type: ChatType.SYSTEM,
191→    sender: "",
192→    message: `No player named "${name}" is currently playing.`,
193→  });
194→}
195→
196→const CHAT_RESTRICTION_MESSAGES: Record<number, string> = {
197→  0: "Chat is restricted",
198→  1: "Chat is throttled",
199→  2: "You have been squelched",
200→  3: "Yell is restricted",
201→};
202→
203→export function handleChatRestricted(conn: WorldConn, r: PacketReader): void {
204→  const restriction = r.uint8();
205→  conn.onMessage?.({
206→    type: ChatType.SYSTEM,
207→    sender: "",
208→    message:
209→      CHAT_RESTRICTION_MESSAGES[restriction] ??
210→      `Chat restriction ${restriction}`,
211→  });
212→}
213→
214→export function handleChatWrongFaction(conn: WorldConn): void {
215→  conn.onMessage?.({
216→    type: ChatType.SYSTEM,
217→    sender: "",
218→    message: "You cannot speak to members of the opposing faction",
219→  });
220→}
221→
222→export function handleServerBroadcast(conn: WorldConn, r: PacketReader): void {
223→  const { message } = parseServerBroadcast(r);
224→  conn.onMessage?.({
225→    type: ChatType.SYSTEM,
226→    sender: "",
227→    message,
228→    origin: "server",
229→  });
230→}
231→
232→export function handleNotification(conn: WorldConn, r: PacketReader): void {
233→  const { message } = parseNotification(r);
234→  conn.onMessage?.({
235→    type: ChatType.SYSTEM,
236→    sender: "",
237→    message,
238→    origin: "notification",
239→  });
240→}
241→
242→export function handlePartyCommandResult(
243→  conn: WorldConn,
244→  r: PacketReader,
245→): void {
246→  const result = parsePartyCommandResult(r);
247→  conn.onGroupEvent?.({
248→    type: "command_result",
249→    operation: result.operation,
250→    target: result.member,
251→    result: result.result,
252→  });
253→}
254→
255→export function handleGroupInviteReceived(
256→  conn: WorldConn,
257→  r: PacketReader,
258→): void {
259→  const invite = parseGroupInvite(r);
260→  conn.onGroupEvent?.({ type: "invite_received", from: invite.name });
261→}
262→
263→export function handleGroupSetLeaderMsg(
264→  conn: WorldConn,
265→  r: PacketReader,
266→): void {
267→  const { name } = parseGroupSetLeader(r);
268→  conn.onGroupEvent?.({ type: "leader_changed", name });
269→}
270→
271→export function handleGroupListMsg(conn: WorldConn, r: PacketReader): void {
272→  const list = parseGroupList(r);
273→  conn.partyMembers.clear();
274→  let leaderName = "";
275→  if (
276→    conn.selfGuidLow === list.leaderGuidLow &&
277→    conn.selfGuidHigh === list.leaderGuidHigh
278→  ) {
279→    leaderName = conn.selfName;
280→  }
281→  for (const m of list.members) {
282→    conn.partyMembers.set(m.name, {
283→      guidLow: m.guidLow,
284→      guidHigh: m.guidHigh,
285→    });
286→    if (
287→      m.guidLow === list.leaderGuidLow &&
288→      m.guidHigh === list.leaderGuidHigh
289→    ) {
290→      leaderName = m.name;
291→    }
292→  }
293→  conn.onGroupEvent?.({
294→    type: "group_list",
295→    members: list.members,
296→    leader: leaderName,
297→  });
298→}
299→
300→export function handleGroupDestroyed(conn: WorldConn): void {
301→  conn.partyMembers.clear();
302→  conn.onGroupEvent?.({ type: "group_destroyed" });
303→}
304→
305→export function handleGroupUninvite(conn: WorldConn): void {
306→  conn.partyMembers.clear();
307→  conn.onGroupEvent?.({ type: "kicked" });
308→}
309→
310→export function handleGroupDeclineMsg(conn: WorldConn, r: PacketReader): void {
311→  const { name } = parseGroupDecline(r);
312→  conn.onGroupEvent?.({ type: "invite_declined", name });
313→}
314→
315→export function handleUpdateObject(conn: WorldConn, r: PacketReader): void {
316→  const entries = parseUpdateObject(r);
317→  for (const entry of entries) {
318→    switch (entry.type) {
319→      case "create": {
320→        const { _changed: _co, ...objFields } = extractObjectFields(
321→          entry.fields,
322→        );
323→        let extraFields: Record<string, unknown> = {};
324→        if (
325→          entry.objectType === ObjectType.UNIT ||
326→          entry.objectType === ObjectType.PLAYER
327→        ) {
328→          const { _changed: _cu, ...rest } = extractUnitFields(entry.fields);
329→          extraFields = rest;
330→        } else if (entry.objectType === ObjectType.GAMEOBJECT) {
331→          const { _changed: _cg, ...rest } = extractGameObjectFields(
332→            entry.fields,
333→          );
334→          extraFields = rest;
335→        }
336→        const cachedName = lookupCachedName(
337→          conn,
338→          entry.guid,
339→          entry.objectType,
340→          objFields.entry,
341→        );
342→        conn.entityStore.create(entry.guid, entry.objectType, {
343→          ...objFields,
344→          ...extraFields,
345→          ...(cachedName ? { name: cachedName } : {}),
346→          ...(entry.position ? { position: entry.position } : {}),
347→          rawFields: new Map(entry.fields),
348→        } as any);
349→        if (!cachedName) {
350→          queryEntityName(conn, entry.guid, entry.objectType, objFields.entry);
351→        }
352→        break;
353→      }
354→      case "values": {
355→        const entity = conn.entityStore.get(entry.guid);
356→        if (!entity) break;
357→        const objFields = extractObjectFields(entry.fields, entity.rawFields);
358→        let extraFields: Record<string, unknown> = {};
359→        if (
360→          entity.objectType === ObjectType.UNIT ||
361→          entity.objectType === ObjectType.PLAYER
362→        ) {
363→          extraFields = extractUnitFields(entry.fields, entity.rawFields);
364→        } else if (entity.objectType === ObjectType.GAMEOBJECT) {
365→          extraFields = extractGameObjectFields(entry.fields);
366→        }
367→        const allChanged = [
368→          ...(objFields._changed || []),
369→          ...((extraFields as any)._changed || []),
370→        ];
371→        const merged: Record<string, unknown> = {};
372→        for (const key of allChanged) {
373→          if (key in extraFields) merged[key] = (extraFields as any)[key];
374→          else if (key in objFields) merged[key] = (objFields as any)[key];
375→        }
376→        conn.entityStore.update(entry.guid, merged);
377→        for (const [k, v] of entry.fields) {
378→          const existing = conn.entityStore.get(entry.guid);
379→          if (existing) existing.rawFields.set(k, v);
380→        }
381→        break;
382→      }
383→      case "movement": {
384→        conn.entityStore.setPosition(entry.guid, entry.position);
385→        break;
386→      }
387→      case "outOfRange": {
388→        for (const guid of entry.guids) conn.entityStore.destroy(guid);
389→        break;
390→      }
391→      case "nearObjects": {
392→        break;
393→      }
394→    }
395→  }
396→}
397→
398→export function handleCompressedUpdateObject(
399→  conn: WorldConn,
400→  r: PacketReader,
401→): void {
402→  const uncompressedSize = r.uint32LE();
403→  const compressed = r.bytes(r.remaining);
404→  const decompressed = inflateSync(compressed);
405→  if (decompressed.length !== uncompressedSize) {
406→    throw new Error(
407→      `Compressed update size mismatch: expected ${uncompressedSize}, got ${decompressed.length}`,
408→    );
409→  }
410→  handleUpdateObject(conn, new PacketReader(new Uint8Array(decompressed)));
411→}
412→
413→export function handleDestroyObject(conn: WorldConn, r: PacketReader): void {
414→  const guid = r.uint64LE();
415→  r.skip(1);
416→  conn.entityStore.destroy(guid);
417→}
