419→export function lookupCachedName(
420→  conn: WorldConn,
421→  guid: bigint,
422→  objectType: number,
423→  entry: number | undefined,
424→): string | undefined {
425→  if (objectType === ObjectType.PLAYER) {
426→    const guidLow = Number(guid & 0xffffffffn);
427→    return conn.nameCache.get(guidLow);
428→  }
429→  if (entry === undefined) return undefined;
430→  if (objectType === ObjectType.UNIT) return conn.creatureNameCache.get(entry);
431→  if (objectType === ObjectType.GAMEOBJECT)
432→    return conn.gameObjectNameCache.get(entry);
433→  return undefined;
434→}
435→
436→export function queryEntityName(
437→  conn: WorldConn,
438→  guid: bigint,
439→  objectType: number,
440→  entry: number | undefined,
441→): void {
442→  if (objectType === ObjectType.PLAYER) {
443→    const guidLow = Number(guid & 0xffffffffn);
444→    const key = `player:${guidLow}`;
445→    if (conn.pendingNameQueries.has(key)) return;
446→    conn.pendingNameQueries.add(key);
447→    const w = new PacketWriter();
448→    w.uint64LE(guid);
449→    sendPacket(conn, GameOpcode.CMSG_NAME_QUERY, w.finish());
450→    return;
451→  }
452→  if (entry === undefined) return;
453→  const key = `${objectType}:${entry}`;
454→  if (conn.pendingNameQueries.has(key)) return;
455→  conn.pendingNameQueries.add(key);
456→  if (objectType === ObjectType.UNIT) {
457→    sendPacket(
458→      conn,
459→      GameOpcode.CMSG_CREATURE_QUERY,
460→      buildCreatureQuery(entry, guid),
461→    );
462→    return;
463→  }
464→  if (objectType === ObjectType.GAMEOBJECT) {
465→    sendPacket(
466→      conn,
467→      GameOpcode.CMSG_GAMEOBJECT_QUERY,
468→      buildGameObjectQuery(entry, guid),
469→    );
470→    return;
471→  }
472→}
