474→export function handleCreatureQueryResponse(
475→  conn: WorldConn,
476→  r: PacketReader,
477→): void {
478→  const result = parseCreatureQueryResponse(r);
479→  conn.pendingNameQueries.delete(`${ObjectType.UNIT}:${result.entry}`);
480→  if (!result.name) return;
481→  conn.creatureNameCache.set(result.entry, result.name);
482→  for (const entity of conn.entityStore.all()) {
483→    if (entity.entry === result.entry && !entity.name) {
484→      conn.entityStore.setName(entity.guid, result.name);
