493→  const result = parseGameObjectQueryResponse(r);
494→  conn.pendingNameQueries.delete(`${ObjectType.GAMEOBJECT}:${result.entry}`);
495→  if (!result.name) return;
496→  conn.gameObjectNameCache.set(result.entry, result.name);
497→  for (const entity of conn.entityStore.all()) {
498→    if (entity.entry === result.entry) {
499→      if (!entity.name) conn.entityStore.setName(entity.guid, result.name);
500→      if (result.gameObjectType !== undefined) {
