525→export function handleContactList(conn: WorldConn, r: PacketReader): void {
526→  const list = parseContactList(r);
527→  const friends: FriendEntry[] = [];
528→  for (const contact of list.contacts) {
529→    if (!(contact.flags & SocialFlag.FRIEND)) continue;
530→    const guidLow = Number(contact.guid & 0xffffffffn);
531→    const name = conn.nameCache.get(guidLow) ?? "";
532→    friends.push({
533→      guid: contact.guid,
534→      name,
535→      note: contact.note,
536→      status: contact.status ?? 0,
537→      area: contact.area ?? 0,
538→      level: contact.level ?? 0,
539→      playerClass: contact.playerClass ?? 0,
540→    });
541→    if (!name && !conn.pendingNameQueries.has(`player:${guidLow}`)) {
542→      conn.pendingNameQueries.add(`player:${guidLow}`);
543→      sendPacket(
544→        conn,
545→        GameOpcode.CMSG_NAME_QUERY,
546→        buildNameQuery(guidLow, Number((contact.guid >> 32n) & 0xffffffffn)),
547→      );
548→    }
549→  }
550→  conn.friendStore.set(friends);
551→
552→  const ignored: IgnoreEntry[] = [];
553→  for (const contact of list.contacts) {
554→    if (!(contact.flags & SocialFlag.IGNORED)) continue;
555→    const guidLow = Number(contact.guid & 0xffffffffn);
556→    const name = conn.nameCache.get(guidLow) ?? "";
557→    ignored.push({ guid: contact.guid, name });
558→    if (!name && !conn.pendingNameQueries.has(`player:${guidLow}`)) {
559→      conn.pendingNameQueries.add(`player:${guidLow}`);
560→      sendPacket(
561→        conn,
562→        GameOpcode.CMSG_NAME_QUERY,
563→        buildNameQuery(guidLow, Number((contact.guid >> 32n) & 0xffffffffn)),
564→      );
565→    }
566→  }
567→  conn.ignoreStore.set(ignored);
568→}
569→
570→export function handleFriendStatus(conn: WorldConn, r: PacketReader): void {
571→  const packet = parseFriendStatus(r);
572→  const guidLow = Number(packet.guid & 0xffffffffn);
573→
574→  switch (packet.result) {
575→    case FriendResult.ADDED_ONLINE:
576→    case FriendResult.ADDED_OFFLINE: {
577→      const name = conn.nameCache.get(guidLow) ?? "";
578→      conn.friendStore.add({
579→        guid: packet.guid,
580→        name,
581→        note: packet.note ?? "",
582→        status: packet.status ?? 0,
583→        area: packet.area ?? 0,
584→        level: packet.level ?? 0,
585→        playerClass: packet.playerClass ?? 0,
586→      });
587→      if (!name && !conn.pendingNameQueries.has(`player:${guidLow}`)) {
588→        conn.pendingNameQueries.add(`player:${guidLow}`);
589→        sendPacket(
590→          conn,
591→          GameOpcode.CMSG_NAME_QUERY,
592→          buildNameQuery(guidLow, Number((packet.guid >> 32n) & 0xffffffffn)),
593→        );
594→      }
595→      break;
596→    }
597→    case FriendResult.ONLINE:
598→      conn.friendStore.update(packet.guid, {
599→        status: packet.status ?? FriendStatus.ONLINE,
600→        area: packet.area ?? 0,
601→        level: packet.level ?? 0,
602→        playerClass: packet.playerClass ?? 0,
603→      });
604→      break;
605→    case FriendResult.OFFLINE:
606→      conn.friendStore.update(packet.guid, { status: FriendStatus.OFFLINE });
607→      break;
608→    case FriendResult.REMOVED:
609→      conn.friendStore.remove(packet.guid);
610→      break;
611→    case FriendResult.IGNORE_ADDED: {
612→      const name = conn.nameCache.get(guidLow) ?? "";
613→      conn.ignoreStore.add({ guid: packet.guid, name });
614→      if (!name && !conn.pendingNameQueries.has(`player:${guidLow}`)) {
615→        conn.pendingNameQueries.add(`player:${guidLow}`);
616→        sendPacket(
617→          conn,
618→          GameOpcode.CMSG_NAME_QUERY,
619→          buildNameQuery(guidLow, Number((packet.guid >> 32n) & 0xffffffffn)),
620→        );
621→      }
622→      break;
623→    }
624→    case FriendResult.IGNORE_REMOVED:
625→      conn.ignoreStore.remove(packet.guid);
626→      break;
627→    case FriendResult.IGNORE_FULL:
628→    case FriendResult.IGNORE_SELF:
629→    case FriendResult.IGNORE_NOT_FOUND:
630→    case FriendResult.IGNORE_ALREADY:
631→    case FriendResult.IGNORE_AMBIGUOUS: {
632→      const name = conn.nameCache.get(guidLow) ?? `guid:${guidLow}`;
633→      conn.onIgnoreEvent?.({
634→        type: "ignore-error",
635→        result: packet.result,
636→        name,
637→      });
638→      break;
639→    }
640→    default: {
641→      const name = conn.nameCache.get(guidLow) ?? `guid:${guidLow}`;
642→      conn.onFriendEvent?.({
643→        type: "friend-error",
644→        result: packet.result,
645→        name,
646→      });
647→      break;
648→    }
649→  }
650→}
