 77→  const state = getSocketState(socket);
 78→  if (state.processing || state.ended) return;
 79→  state.processing = true;
 80→  ctx.onActivity?.();
 81→  const cmd = parseIpcCommand(line);
 82→  if (!cmd) {
 83→    writeLines(socket, ["ERR unknown command"]);
 84→    state.ended = true;
 85→    state.processing = false;
 86→    socket.end();
 87→    return;
 88→  }
