107→export function startDaemonServer(args: DaemonServerArgs): DaemonServer {
108→  const { handle, sock, log, onActivity, onStop } = args;
109→  const events = new RingBuffer<EventEntry>(1000);
110→  handle.onMessage((msg) => onChatMessage(msg, events, log));
111→  handle.onGroupEvent((event) => onGroupEvent(event, events, log));
112→  handle.onEntityEvent((event) => onEntityEvent(event, events, log));
113→  handle.onFriendEvent((event) => onFriendEvent(event, events, log));
114→  handle.onIgnoreEvent((event) => onIgnoreEvent(event, events, log));
115→
116→  let cleaned = false;
117→  function cleanup(): void {
118→    if (cleaned) return;
119→    cleaned = true;
120→    handle.close();
121→    server.stop();
122→    unlink(sock).catch(() => {});
123→  }
124→
125→  const ctx: ServerCtx = { handle, events, cleanup, onActivity, onStop };
126→  const server = Bun.listen({
127→    unix: sock,
128→    socket: { data: (socket, data) => onSocketData(ctx, socket, data) },
129→  });
130→
131→  return { server, events, cleanup };
132→}
