134→function buildClientConfig(cfg: Awaited<ReturnType<typeof readConfig>>) {
135→  return {
136→    host: cfg.host,
137→    port: cfg.port,
138→    account: cfg.account.toUpperCase(),
139→    password: cfg.password.toUpperCase(),
140→    character: cfg.character,
141→    language: cfg.language,
142→  };
143→}
144→
145→async function prepareDaemonPaths(): Promise<{ sock: string; pid: string }> {
146→  const sock = socketPath();
147→  const pid = pidPath();
148→  await mkdir(runtimeDir(), { recursive: true });
149→  await writeFile(pid, String(process.pid));
150→  await unlink(sock).catch(() => {});
151→  return { sock, pid };
152→}
153→
154→export async function startDaemon(client?: DaemonClient): Promise<void> {
155→  const cfg = await readConfig();
156→  const { sock, pid } = await prepareDaemonPaths();
157→
158→  const clientCfg = buildClientConfig(cfg);
159→  const auth = await (client
160→    ? client.authHandshake(clientCfg)
161→    : authWithRetry(clientCfg));
162→  const handle = await (client?.worldSession ?? worldSession)(clientCfg, auth);
163→  const log = new SessionLog(logPath());
164→
165→  let lastActivity = Date.now();
166→  const timeoutMs = cfg.timeout_minutes * 60_000;
167→  let cleaned = false;
168→
169→  function cleanup(): void {
170→    if (cleaned) return;
171→    cleaned = true;
172→    stopServer();
173→    clearInterval(idleCheck);
174→    unlink(pid).catch(() => {});
175→  }
176→
177→  function exit(): void {
178→    cleanup();
179→    process.exit(0);
180→  }
181→
182→  const { cleanup: stopServer } = startDaemonServer({
183→    handle,
184→    sock,
185→    log,
186→    onActivity: () => {
187→      lastActivity = Date.now();
188→    },
189→    onStop: exit,
190→  });
191→
192→  const idleCheck = setInterval(() => {
193→    if (Date.now() - lastActivity > timeoutMs) exit();
194→  }, 60_000);
195→  process.on("SIGTERM", cleanup);
196→  process.on("SIGINT", cleanup);
197→
198→  await handle.closed;
199→  cleanup();
200→}
