        type: "command_result",
        operation: PartyOperation.INVITE,
        target: "Voidtrix",
        result: PartyResult.SUCCESS,
      }),
    ).toBe("[group] Invited Voidtrix");
  });

  test("invite failure", () => {
    expect(
      formatGroupEvent({
        type: "command_result",
        operation: PartyOperation.INVITE,
        target: "Voidtrix",
        result: PartyResult.BAD_PLAYER_NAME,
      }),
    ).toBe("[group] Cannot invite Voidtrix: player not found");
  });

