    expect(
      formatGroupEvent({
        type: "command_result",
        operation: PartyOperation.UNINVITE,
        target: "Voidtrix",
        result: PartyResult.SUCCESS,
      }),
    ).toBe("[group] Removed Voidtrix from group");
  });

  test("uninvite failure", () => {
